// ---------- FLASHCARDS (Begriffe) ----------
const FLASHCARDS = [
  { topic: "tarifvertrag", front: "Tarifautonomie", back: "Tarifvertragsparteien sind unabhängig vom Staat und dürfen selbstständig Tarifverträge aushandeln und abschließen. Der Staat hat kein Eingriffsrecht." },
  { topic: "tarifvertrag", front: "Allgemeinverbindlichkeit", back: "Auf Antrag der Tarifparteien kann das Bundesministerium für Arbeit und Soziales einen Tarifvertrag für allgemeinverbindlich erklären. Er bindet dann auch nicht organisierte Arbeitgeber und Arbeitnehmer." },
  { topic: "tarifvertrag", front: "Unabdingbarkeit des Tarifvertrags", back: "Die Regelungen des Tarifvertrags sind Mindestleistungen. Sie dürfen im Einzelarbeitsvertrag nicht unterschritten werden (auch nicht mit Zustimmung des AN). Verbesserungen sind erlaubt (übertarifliche Leistungen)." },
  { topic: "tarifvertrag", front: "Friedenspflicht", back: "Während der Laufzeit eines Tarifvertrags dürfen keine Arbeitskampfmaßnahmen (Streik, Aussperrung) zu den bereits geregelten Themen stattfinden." },
  { topic: "tarifvertrag", front: "Sozialpartner", back: "Arbeitgeberverbände + Gewerkschaften – gemeinsame Bezeichnung für die Tarifvertragsparteien." },
  { topic: "tarifvertrag", front: "Tarifkommission", back: "Gruppe aus Vertretern der Gewerkschaften bzw. Arbeitgeberverbände, die die Tarifverhandlungen führt." },
  { topic: "tarifvertrag", front: "Günstigkeitsprinzip", back: "Der Einzelarbeitsvertrag bzw. die Betriebsvereinbarung darf gegenüber dem Tarifvertrag nur zugunsten des Arbeitnehmers abweichen, niemals zu seinen Ungunsten." },
  { topic: "tarifvertrag", front: "Lohn-/Gehaltstarifvertrag", back: "Regelt Höhe der Lohn-/Gehaltsgruppen, Eckelohn, Laufzeit meist ca. 1 Jahr." },
  { topic: "tarifvertrag", front: "Manteltarifvertrag (Rahmentarifvertrag)", back: "Regelt Arbeitszeit, Urlaub, Kündigung, Mehrarbeit, Zuschläge – Laufzeit meist 3–5 Jahre." },
  { topic: "tarifvertrag", front: "Warum Aufspaltung in Lohn-/Manteltarifvertrag?", back: "Damit bei jährlichen Lohnerhöhungen nicht auch die langfristig geltenden Bestimmungen (z. B. Urlaub, Kündigungsfristen) jedes Mal neu verhandelt werden müssen." },
  { topic: "streik", front: "Warnstreik", back: "Arbeitnehmer legen für kurze Zeit die Arbeit nieder, um Streikbereitschaft anzukündigen (z. B. während laufender Tarifverhandlungen)." },
  { topic: "streik", front: "Wilder Streik", back: "Streik ohne Urabstimmung und ohne Genehmigung der Gewerkschaft. Ist rechtswidrig – Folgen: Abmahnung oder fristlose Kündigung, kein Entgelt für die Streikzeit." },
  { topic: "streik", front: "Schwerpunktstreik", back: "Es werden gezielt nur die wichtigsten/relevantesten Betriebe eines Wirtschaftszweigs bestreikt (spart Streikgeld, erzielt maximale Wirkung)." },
  { topic: "streik", front: "Totaler Streik (Flächenstreik)", back: "Alle Betriebe eines ganzen Wirtschaftsbereichs/-zweigs werden bestreikt." },
  { topic: "streik", front: "Generalstreik", back: "Alle Arbeitnehmer eines ganzen Landes streiken – legt die gesamte Wirtschaft lahm. In Deutschland nicht praktiziert/faktisch nicht erlaubt." },
  { topic: "streik", front: "Sympathiestreik", back: "Streik zur Solidarität mit Arbeitnehmern eines anderen Wirtschaftszweigs, um deren Streik zu unterstützen." },
  { topic: "streik", front: "Urabstimmung", back: "Abstimmung der Gewerkschaftsmitglieder über die Durchführung eines Arbeitskampfes nach gescheiterter Tarifverhandlung. Streik nur, wenn 75 % zustimmen; Streikende bei 25 % Zustimmung." },
  { topic: "streik", front: "Aussperrung", back: "Kampfmittel des Arbeitgebers: Arbeitnehmer werden vorübergehend vom Betrieb ausgeschlossen und erhalten keinen Lohn – betrifft auch nicht gewerkschaftlich organisierte AN." },
  { topic: "ausbildung", front: "Ausbildungsordnung", back: "Rechtsverordnung und rechtliches Fundament der dualen Ausbildung. Legt bundeseinheitliche Mindeststandards fest: Berufsbezeichnung, Ausbildungsdauer, Ausbildungsberufsbild, Ausbildungsrahmenplan, Prüfungsanforderungen." },
  { topic: "ausbildung", front: "Ausbildungsrahmenplan", back: "Praktischer Fahrplan zur Umsetzung der Ausbildungsordnung im Betrieb. Enthält sachliche Gliederung (Inhalte/Themen) und zeitliche Gliederung (wann/wie lange). Teil der Ausbildungsordnung, aber flexibel im Betrieb umsetzbar." },
  { topic: "ausbildung", front: "Sachliche Gliederung", back: "Strukturiert alle wesentlichen Ausbildungsinhalte, Themen und Fähigkeiten; legt Themenfelder, Lernziele und Kompetenzen fest." },
  { topic: "ausbildung", front: "Zeitliche Gliederung", back: "Legt fest, wann und wie lange Ausbildungsinhalte vermittelt werden; beschreibt die Progression der Ausbildung." },
  { topic: "ausbildung", front: "Rahmenlehrplan", back: "Legt die schulischen Ausbildungsinhalte für die Berufsschule fest (nach Lernfeldern strukturiert). Wird von der Kultusministerkonferenz (KMK) beschlossen." },
  { topic: "ausbildung", front: "Probezeit (Dauer)", back: "Mindestens 1, höchstens 4 Monate. Während der Probezeit kann jederzeit ohne Frist und ohne Angabe von Gründen gekündigt werden." },
  { topic: "ausbildung", front: "Kündigung nach der Probezeit (Azubi)", back: "Der Azubi kann mit einer Frist von 4 Wochen schriftlich kündigen (z. B. bei Berufswechsel). Der Ausbildende kann nur noch fristlos aus wichtigem Grund kündigen (z. B. Diebstahl, Beleidigung)." },
  { topic: "ausbildung", front: "Duales System", back: "Ausbildung an zwei Lernorten: Betrieb (Praxis) und Berufsschule (Theorie). Ziel: praxisnahe und abwechslungsreiche Ausbildung." },
  { topic: "ausbildung", front: "Fürsorgepflicht des Ausbildenden", back: "Zahlung der Sozialversicherungsbeiträge, Einhaltung des Jugendarbeitsschutzgesetzes, Beachtung der Unfallschutzbestimmungen, keine Gesundheitsgefährdung." },
  { topic: "ausbildung", front: "Pflichten des Auszubildenden", back: "Lernpflicht, Sorgfaltspflicht, Berufsschulpflicht, Ausbildungsnachweis (Berichtsheft) führen, Verschwiegenheitspflicht, Gehorsamspflicht (Weisungen befolgen)." },
  { topic: "betriebsrat", front: "Betriebsvereinbarung", back: "Schriftliche Vereinbarung zwischen Geschäftsleitung und Betriebsrat über Rechte/Pflichten, die nicht bereits durch Tarifvertrag geregelt sind (z. B. gleitende Arbeitszeit). Muss von beiden unterschrieben und im Betrieb ausgehängt werden." },
  { topic: "betriebsrat", front: "Mitbestimmung – sozialer Bereich", back: "Echtes Mitbestimmungsrecht: ohne Zustimmung des BR keine Maßnahme möglich. Beispiele: Urlaubsplan, Arbeitszeit, Entlohnungsgrundsätze." },
  { topic: "betriebsrat", front: "Mitbestimmung – personeller Bereich", back: "BR kann bei schwerwiegenden Gründen die Zustimmung verweigern; letzte Entscheidung trifft das Arbeitsgericht. Beispiele: Kündigungen, Einstellungen, Versetzungen." },
  { topic: "betriebsrat", front: "Mitbestimmung – wirtschaftlicher Bereich", back: "Nur Informationsrecht: BR muss informiert werden, seine Zustimmung ist nicht erforderlich. Beispiele: Investitionen, Stilllegung/Verlegung des Betriebs, neue Produkte." },
  { topic: "betriebsrat", front: "Wahlberechtigung (Betriebsrat)", back: "Alle Arbeitnehmer des Betriebs, die das 16. Lebensjahr vollendet haben (§ 7 BetrVG)." },
  { topic: "betriebsrat", front: "Wählbarkeit (Betriebsrat)", back: "Alle Wahlberechtigten, die das 18. Lebensjahr vollendet haben und mindestens 6 Monate dem Betrieb angehören (§ 8 BetrVG)." },
  { topic: "betriebsrat", front: "Amtszeit des Betriebsrats", back: "4 Jahre (§ 21 BetrVG). Betriebsratswahlen finden deshalb regelmäßig zwischen dem 1. März und 31. Mai statt." },
  { topic: "betriebsrat", front: "Voraussetzung für die Wahl eines Betriebsrats", back: "Der Betrieb muss in der Regel mindestens 5 ständige wahlberechtigte Arbeitnehmer haben, von denen 3 wählbar sind (§ 1 BetrVG)." },
  { topic: "betriebsrat", front: "Vollständige Freistellung eines Betriebsratsmitglieds", back: "Ab 200 Arbeitnehmern muss mindestens 1 Betriebsratsmitglied komplett von der Arbeit freigestellt werden (§ 38 BetrVG) – wird trotzdem weiterbezahlt." },
  { topic: "betriebsrat", front: "Wirtschaftsausschuss – Pflicht", back: "Muss in Betrieben mit mehr als 100 Arbeitnehmern eingerichtet werden. Der Arbeitgeber informiert dort über wirtschaftliche/finanzielle Angelegenheiten, der Betriebsrat berät mit." },
  { topic: "betriebsrat", front: "Betriebsversammlung – Häufigkeit", back: "Muss mindestens 1x pro Quartal (4x im Jahr) stattfinden. Pflicht: Der Betriebsrat legt dabei Rechenschaft über seine Tätigkeit ab." },
  { topic: "betriebsrat", front: "§ 102 BetrVG – Anhörung bei Kündigung", back: "Der Betriebsrat ist vor jeder Kündigung anzuhören, der Arbeitgeber muss die Gründe mitteilen. Eine Kündigung ohne Anhörung des BR ist unwirksam." },
  { topic: "betriebsrat", front: "Pflichten des Arbeitgebers gegenüber dem Arbeitnehmer (BetrVG)", back: "Beschwerden entgegennehmen, Einsicht in die Personalakte gewähren, über Gefahren/Unfallschutz informieren, Zusammensetzung des Verdienstes erläutern, auf Verlangen Leistung beurteilen und über Aufstiegsmöglichkeiten informieren." },
  { topic: "betriebsrat", front: "Pflichten des Arbeitgebers gegenüber dem Betriebsrat", back: "Betriebsrat für seine Aufgaben freistellen (bei Weiterbezahlung), Räume und Gegenstände für die BR-Arbeit zur Verfügung stellen." },
  { topic: "jav", front: "Rechtsgrundlage der JAV", back: "Das Betriebsverfassungsgesetz (BetrVG) regelt die Wahl der Jugend- und Auszubildendenvertretung." },
  { topic: "jav", front: "Voraussetzung für eine JAV-Wahl", back: "Im Betrieb müssen mindestens 5 Arbeitnehmer unter 18 Jahren oder Auszubildende beschäftigt sein." },
  { topic: "jav", front: "Wahlberechtigung (JAV)", back: "Alle Jugendlichen (unter 18) und alle Auszubildenden des Betriebs, unabhängig vom Alter." },
  { topic: "jav", front: "Wählbarkeit (JAV)", back: "Arbeitnehmer, die das 25. Lebensjahr noch nicht überschritten haben, sowie alle Auszubildenden des Betriebs." },
  { topic: "jav", front: "Amtszeit der JAV", back: "2 Jahre. Die regelmäßigen Wahlen finden im Herbst statt." },
  { topic: "jav", front: "Hauptaufgabe der JAV", back: "Die besonderen Belange der Jugendlichen und Auszubildenden gegenüber dem Arbeitgeber zu vertreten." },
  { topic: "jav", front: "JAV und Betriebsrat", back: "Die JAV verhandelt nicht direkt mit dem Arbeitgeber, sondern muss ihre Interessen über den Betriebsrat durchsetzen. Ein JAV-Mitglied darf an jeder Betriebsratssitzung teilnehmen; bei Themen, die überwiegend Jugendliche/Azubis betreffen, sind alle JAV-Mitglieder stimmberechtigt." },
  { topic: "jav", front: "Jugend- und Auszubildendenversammlung", back: "Findet vor jeder Betriebsversammlung statt. Ein anderer Zeitpunkt ist nur im Einvernehmen mit Betriebsrat und Arbeitgeber möglich." },
  { topic: "jarbschg", front: "Geltungsbereich JArbSchG", back: "Gilt für alle Personen, die noch nicht 18 Jahre alt sind (§ 1)." },
  { topic: "jarbschg", front: "Kind vs. Jugendlicher (§ 2 JArbSchG)", back: "Kind: wer noch keine 15 Jahre alt ist. Jugendlicher: wer 15, aber noch keine 18 Jahre alt ist. Kinderarbeit ist grundsätzlich verboten." },
  { topic: "jarbschg", front: "Maximale Arbeitszeit Jugendlicher", back: "Grundsätzlich max. 8 Stunden täglich (Ausnahmen bis 8,5 Std. bei Ausgleich in derselben Woche) und max. 40 Stunden wöchentlich (§ 8)." },
  { topic: "jarbschg", front: "Schichtzeit (§ 12 JArbSchG)", back: "Arbeitszeit inklusive Pausen – darf für Jugendliche höchstens 10 Stunden betragen." },
  { topic: "jarbschg", front: "Ruhepausen nach Arbeitszeit (§ 11 JArbSchG)", back: "4,5–6 Stunden Arbeitszeit: mind. 30 Minuten Pause. Über 6 Stunden: mind. 60 Minuten Pause. Spätestens nach 4,5 Std. muss die erste Pause eingelegt werden." },
  { topic: "jarbschg", front: "Ruhezeit (§ 13 JArbSchG)", back: "Zwischen Feierabend und dem Beginn der nächsten Beschäftigung müssen mindestens 12 Stunden liegen." },
  { topic: "jarbschg", front: "Arbeitszeiten Jugendlicher (§ 14 JArbSchG)", back: "Grundsätzlich nur zwischen 6 und 20 Uhr, an Heiligabend/Silvester nicht nach 14 Uhr. Branchenausnahmen möglich (z. B. Bäckerei ab 4 Uhr)." },
  { topic: "jarbschg", front: "Arbeitstage pro Woche (§ 15 JArbSchG)", back: "Jugendliche dürfen in der Regel an maximal 5 Tagen pro Woche beschäftigt werden." },
  { topic: "jarbschg", front: "Urlaubsanspruch nach Alter (§ 19 JArbSchG)", back: "Zu Beginn des Kalenderjahres unter 16 Jahre: mind. 30 Werktage. Unter 17 Jahre: mind. 27 Werktage. Unter 18 Jahre: mind. 25 Werktage." },
  { topic: "jarbschg", front: "Berufsschulzeit als Arbeitstag", back: "Mehr als 5 Unterrichtsstunden an einem Berufsschultag entsprechen einem vollen Arbeitstag – danach darf nicht mehr im Betrieb gearbeitet werden." },
  { topic: "jarbschg", front: "Freistellung vor der Abschlussprüfung (§ 10 JArbSchG)", back: "Jugendliche müssen an dem Arbeitstag freigestellt werden, der der schriftlichen Abschlussprüfung unmittelbar vorangeht." },
  { topic: "jarbschg", front: "Ärztliche Untersuchungen (§ 32/33 JArbSchG)", back: "Erstuntersuchung vor Beschäftigungsbeginn Pflicht, Nachuntersuchung spätestens 1 Jahr nach Aufnahme der Beschäftigung." },
  { topic: "jarbschg", front: "Verbotene Arbeiten für Jugendliche (§ 22 JArbSchG)", back: "Akkordarbeit sowie gefährliche, sittlich gefährdende und Jugendliche übersteigende schwere Arbeiten sind grundsätzlich verboten." },
  { topic: "jarbschg", front: "Aufsicht über den Jugendarbeitsschutz", back: "Beratung und Überwachung erfolgen durch das Gewerbeaufsichtsamt / Amt für Arbeitsschutz." },
  { topic: "betriebsvereinbarung", front: "Betriebsvereinbarung – Definition", back: "Schriftliche Vereinbarung zwischen Arbeitgeber und Betriebsrat eines Betriebs über Rechte/Pflichten, die nicht bereits durch Tarifvertrag geregelt sind." },
  { topic: "betriebsvereinbarung", front: "Formvorschrift für Betriebsvereinbarungen", back: "Müssen schriftlich abgefasst und für jeden sichtbar im Betrieb ausgehängt (veröffentlicht) werden." },
  { topic: "betriebsvereinbarung", front: "Verhältnis Betriebsvereinbarung – Tarifvertrag", back: "Eine Betriebsvereinbarung darf tarifliche Bestimmungen nur verbessern, nicht verschlechtern – außer der Tarifvertrag erlaubt es ausdrücklich durch eine Öffnungsklausel." },
  { topic: "betriebsvereinbarung", front: "Bekannteste Form der Betriebsvereinbarung", back: "Die Betriebsordnung – regelt z. B. Rauchverbot, Arbeitskleidung, Arbeitszeiten, Ruhepausen." },
  { topic: "betriebsvereinbarung", front: "Typische Inhalte einer Betriebsvereinbarung", back: "Beginn/Ende der täglichen Arbeitszeit und Pausen, Unfallverhütungsvorschriften, betriebliche Sozialeinrichtungen, Urlaubspläne, Sonderzahlungen (z. B. Urlaubsgeld)." },
  { topic: "betriebsvereinbarung", front: "Rücknahme einer Betriebsvereinbarung", back: "Der Arbeitgeber kann eine Betriebsvereinbarung nicht allein zurücknehmen – der Betriebsrat muss der Rücknahme zustimmen." },
  { topic: "betriebsvereinbarung", front: "Kündigungsfrist einer Betriebsvereinbarung", back: "Grundsätzlich 3 Monate, sofern nichts anderes vereinbart wurde." },
  { topic: "klausur", front: "Bundesvereinigung der Deutschen Arbeitgeberverbände (BDA)", back: "Vertritt die wirtschafts- und sozialpolitischen Interessen der Arbeitgeber gegenüber Parlament und Regierung." },
  { topic: "klausur", front: "Ziel eines Arbeitgeberverbands", back: "Verbesserung der Wettbewerbsfähigkeit der Mitgliedsbetriebe; freiwilliger Zusammenschluss von Arbeitgebern zur Wahrung ihrer Interessen." },
  { topic: "klausur", front: "Vorteil der Gewerkschaftsmitgliedschaft für Arbeitnehmer", back: "Anspruch auf kostenlosen arbeitsrechtlichen Rechtsschutz." },
  { topic: "klausur", front: "Zuständige Stelle für die Eintragung des Ausbildungsvertrags", back: "Die Industrie- und Handelskammer (IHK) am Sitz des Ausbildungsbetriebs – unverzüglich nach Vertragsabschluss, spätestens vor Ausbildungsbeginn." },
  { topic: "klausur", front: "Kostenlose Ausbildungsmittel", back: "Der Ausbildende muss Werkzeuge, Werkstoffe und erforderliche persönliche Schutzausrüstung kostenlos stellen – allgemeine Freizeitkleidung gehört nicht dazu." },
  { topic: "klausur", front: "Ende des Ausbildungsverhältnisses", back: "Endet automatisch mit Bestehen der Abschlussprüfung bzw. Bekanntgabe des Prüfungsergebnisses – ohne automatischen Anspruch auf Übernahme." },
  { topic: "klausur", front: "Kündigung während der Probezeit (§ 22 BBiG)", back: "Jederzeit möglich, ohne Einhaltung einer Frist und ohne Angabe von Gründen." },
  { topic: "klausur", front: "Arbeitsrechtliche Rangfolge", back: "Gesetz > Tarifvertrag > Betriebsvereinbarung > Einzelarbeitsvertrag. Jede niedrigere Ebene darf die höhere nur zugunsten des Arbeitnehmers verbessern, nie verschlechtern." },
  { topic: "rewe-aufgaben", front: "Kernaufgabe des industriellen Rechnungswesens", back: "Beschaffung der Werkstoffe/Betriebsmittel, Produktion der Erzeugnisse und Absatz zahlenmäßig erfassen, überwachen und auswerten." },
  { topic: "rewe-aufgaben", front: "Dokumentationsaufgabe", back: "Zeitlich und sachlich geordnete Aufzeichnung aller Geschäftsvorfälle aufgrund von Belegen." },
  { topic: "rewe-aufgaben", front: "Rechenschaftslegungs- und Informationsaufgabe", back: "Jährliche Rechenschaftslegung und Erstellung des Jahresabschlusses; informiert Geschäftsleitung, Gläubiger und Öffentlichkeit über Vermögens-, Schulden- und Erfolgslage." },
  { topic: "rewe-aufgaben", front: "Kontrollaufgabe", back: "Überwachung der Wirtschaftlichkeit und Zahlungsfähigkeit des Unternehmens." },
  { topic: "rewe-aufgaben", front: "Dispositionsaufgabe", back: "Bereitstellung des aufbereiteten Zahlenmaterials als Planungs- und Entscheidungsgrundlage." },
  { topic: "rewe-aufgaben", front: "Buchführung (Finanzbuchhaltung)", back: "Erfasst die Wertströme zwischen Unternehmen und Außenwelt, ermittelt den Erfolg (Gewinn/Verlust) durch Gegenüberstellung von Aufwendungen und Erträgen. Unternehmensbezogene Zeitrechnung (i. d. R. 1 Jahr)." },
  { topic: "rewe-aufgaben", front: "Kosten- und Leistungsrechnung (KLR)", back: "Betriebsbezogene Betrachtung, ermittelt den Erfolg aus Produktion und Verkauf, ermöglicht die Preiskalkulation. Stück- und Zeitrechnung (oft Monat)." },
  { topic: "rewe-aufgaben", front: "Statistik (im Rechnungswesen)", back: "Bereitet die Zahlen aus Buchführung und KLR grafisch/tabellarisch auf und wertet sie aus – Basis für Zeit- und Betriebsvergleich." },
  { topic: "rewe-aufgaben", front: "Planung (im Rechnungswesen)", back: "Wertet inner- und außerbetriebliche Daten aus, erstellt Einzelpläne (z. B. Absatz-, Beschaffungs-, Finanzplan) – Führungs- und Kontrollinstrument per Soll-Ist-Vergleich." },
  { topic: "rewe-buchfuehrung-inventur", front: "Buchführungspflicht (§ 238 HGB)", back: "Jeder Kaufmann ist verpflichtet, Bücher zu führen und seine Handelsgeschäfte sowie die Lage seines Vermögens nach den GoB ersichtlich zu machen." },
  { topic: "rewe-buchfuehrung-inventur", front: "Befreiung von der Buchführungspflicht (§ 241a HGB)", back: "Einzelkaufleute, die an zwei aufeinanderfolgenden Abschlussstichtagen nicht mehr als 800.000 € Umsatzerlöse und 80.000 € Jahresüberschuss aufweisen, müssen die §§ 238–241 HGB nicht anwenden." },
  { topic: "rewe-buchfuehrung-inventur", front: "Buchführungspflicht nach Steuerrecht (§ 141 AO)", back: "Gilt bei Umsätzen über 800.000 € im Kalenderjahr oder einem Gewinn aus Gewerbebetrieb bzw. Land-/Forstwirtschaft über 80.000 €." },
  { topic: "rewe-buchfuehrung-inventur", front: "Istkaufmann (§ 1 HGB)", back: "Wer ein Handelsgewerbe betreibt (kaufmännisch eingerichteter Geschäftsbetrieb). Die Eintragung ins Handelsregister ist nur deklaratorisch (bestätigend)." },
  { topic: "rewe-buchfuehrung-inventur", front: "Kannkaufmann (§ 2 HGB)", back: "Kleingewerbetreibende, die sich freiwillig ins Handelsregister eintragen lassen können. Die Eintragung ist konstitutiv (rechtsbegründend)." },
  { topic: "rewe-buchfuehrung-inventur", front: "Formkaufmann (§ 6 HGB)", back: "Handelsgesellschaften (z. B. GmbH, AG) sind Kaufleute kraft ihrer Rechtsform. Die Eintragung ist konstitutiv." },
  { topic: "rewe-buchfuehrung-inventur", front: "GoB – Allgemeiner Grundsatz", back: "Die Buchführung muss einem sachverständigen Dritten in angemessener Zeit einen Überblick über die Geschäftsvorfälle und die Lage des Unternehmens vermitteln (§ 238 HGB)." },
  { topic: "rewe-buchfuehrung-inventur", front: "Aufbewahrungsfrist für Rechnungen", back: "10 Jahre (§ 147 AO / § 257 HGB). Die Frist beginnt mit dem Ende des Kalenderjahres, in dem die Rechnung ausgestellt wurde." },
  { topic: "rewe-buchfuehrung-inventur", front: "Inventur", back: "Die mengen- und wertmäßige Bestandsaufnahme aller Vermögensteile und Schulden eines Unternehmens zu einem bestimmten Zeitpunkt." },
  { topic: "rewe-buchfuehrung-inventur", front: "Körperliche Inventur", back: "Mengenmäßige Aufnahme aller körperlich vorhandenen Vermögensgegenstände durch Zählen, Messen, Wiegen." },
  { topic: "rewe-buchfuehrung-inventur", front: "Buchinventur (buchmäßige Inventur)", back: "Wertmäßige Erfassung aller nicht körperlich vorhandenen Vermögensgegenstände und Schulden anhand von Belegen, z. B. Forderungen, Bankguthaben, Darlehen." },
  { topic: "rewe-buchfuehrung-inventur", front: "Zeitnahe Stichtagsinventur", back: "Körperliche Bestandsaufnahme bis zu 10 Tage vor oder nach dem Bilanzstichtag; Zu-/Abgänge werden wert- und mengenmäßig fortgeschrieben bzw. zurückgerechnet." },
  { topic: "rewe-buchfuehrung-inventur", front: "Zeitlich verlegte Inventur (§ 241 Abs. 3 HGB)", back: "Körperliche Bestandsaufnahme innerhalb der letzten 3 Monate vor oder der ersten 2 Monate nach dem Bilanzstichtag, wertmäßige Fortschreibung/Rückrechnung." },
  { topic: "rewe-buchfuehrung-inventur", front: "Permanente Inventur (freiwillig)", back: "Fortlaufende Bestandsaufnahme über das ganze Geschäftsjahr per Lagerbuchführung; mindestens 1x jährlich ist eine körperliche Stichprobe erforderlich." },
  { topic: "rewe-buchfuehrung-inventur", front: "Stichprobeninventur (§ 241 Abs. 1 HGB)", back: "Stichproben werden mittels anerkannter mathematisch-statistischer Verfahren körperlich aufgenommen und bewertet; das Ergebnis wird auf den Gesamtbestand hochgerechnet." },
  { topic: "rewe-inventar", front: "Inventar", back: "Ein ausführliches, nach § 240 HGB vorgeschriebenes Bestandsverzeichnis, das alle Vermögensteile und Schulden eines Unternehmens zu einem bestimmten Zeitpunkt nach Art, Menge und Wert aufweist." },
  { topic: "rewe-inventar", front: "Gliederung des Inventars", back: "A. Vermögen, B. Schulden, C. Ermittlung des Eigenkapitals (Reinvermögen). Erstellt in Staffelform (Vorspalte für Einzelwerte, Hauptspalte für Summen)." },
  { topic: "rewe-inventar", front: "Anlagevermögen im Inventar (4 Positionen)", back: "1. Grundstücke und Gebäude, 2. Technische Anlagen und Maschinen, 3. Fuhrpark, 4. Betriebs- und Geschäftsausstattung." },
  { topic: "rewe-inventar", front: "Umlaufvermögen im Inventar (8 Positionen)", back: "1. Rohstoffe, 2. Hilfsstoffe, 3. Betriebsstoffe, 4. Unfertige Erzeugnisse, 5. Fertige Erzeugnisse, 6. Forderungen a. LL, 7. Bankguthaben, 8. Kassenbestand." },
  { topic: "rewe-inventar", front: "Ordnung des Vermögens im Inventar", back: "Nach steigender Liquidität (Flüssigkeit) – Anlagevermögen vor Umlaufvermögen." },
  { topic: "rewe-inventar", front: "Langfristige Verbindlichkeiten", back: "Schulden mit langer Laufzeit, z. B. Hypothekendarlehen, Darlehen." },
  { topic: "rewe-inventar", front: "Kurzfristige Verbindlichkeiten", back: "Schulden mit kurzer Laufzeit, z. B. Verbindlichkeiten aus Lieferungen und Leistungen (a. LL)." },
  { topic: "rewe-inventar", front: "Ordnung der Schulden im Inventar", back: "Nach ihrer Fälligkeit – langfristige vor kurzfristigen Verbindlichkeiten." },
  { topic: "rewe-inventar", front: "Eigenkapital / Reinvermögen (Inventar)", back: "Summe des Vermögens minus Summe der Schulden." },
  { topic: "rewe-inventar", front: "Abkürzung a. LL", back: "aus Lieferungen und Leistungen (Forderungen bzw. Verbindlichkeiten aus dem Waren-/Leistungsverkehr)." },
  { topic: "rewe-inventar", front: "Abkürzung TAM", back: "Technische Anlagen und Maschinen." },
  { topic: "rewe-inventar", front: "Abkürzung BGA", back: "Betriebs- und Geschäftsausstattung." },
  { topic: "rewe-bilanz", front: "Bilanz", back: "Eine verkürzte, übersichtliche Darstellung des Inventars in Kontoform, vorgeschrieben nach § 242 HGB (Inventar allein ist zu unübersichtlich)." },
  { topic: "rewe-bilanz", front: "Aktiva", back: "Linke Seite der Bilanz. Zeigt das Vermögen (Anlage- und Umlaufvermögen), geordnet nach Liquidität. Beantwortet: Wo ist das Kapital angelegt? (Investierung)" },
  { topic: "rewe-bilanz", front: "Passiva", back: "Rechte Seite der Bilanz. Zeigt das Kapital (Eigenkapital + Fremdkapital), geordnet nach Fälligkeit. Beantwortet: Woher stammt das Kapital? (Finanzierung)" },
  { topic: "rewe-bilanz", front: "Bilanzgleichung", back: "Vermögen = Kapital = Eigenkapital + Fremdkapital. Beide Bilanzseiten sind immer gleich groß." },
  { topic: "rewe-bilanz", front: "Eigenkapital aus der Bilanzgleichung", back: "Eigenkapital = Vermögen − Fremdkapital." },
  { topic: "rewe-bilanz", front: "Fremdkapital aus der Bilanzgleichung", back: "Fremdkapital = Vermögen − Eigenkapital." },
  { topic: "rewe-bilanz", front: "Funktion des Anlagevermögens", back: "Dient dem Unternehmen dauerhaft/langfristig und bildet die Basis der Betriebsbereitschaft." },
  { topic: "rewe-bilanz", front: "Funktion des Umlaufvermögens", back: "Dient dem Unternehmen nur kurzfristig und unterliegt ständiger Veränderung durch Leistungserstellung und -verwertung." },
  { topic: "excel-grundlagen", front: "Zahl erkennen (Excel)", back: "Zahlen werden mit Komma als Dezimaltrennzeichen eingegeben (z. B. 12,50) und als rechenbarer Wert erkannt – rechtsbündig ausgerichtet." },
  { topic: "excel-grundlagen", front: "Text erkennen (Excel)", back: "Zahlen mit Punkt statt Komma (z. B. 12.50) werden von Excel als Text erkannt, nicht als rechenbare Zahl – linksbündig ausgerichtet." },
  { topic: "excel-grundlagen", front: "Excel-Syntax", back: "Jede Formel beginnt mit einem Gleichheitszeichen, z. B. =SUMME(A1:B1) oder =SUMME(A1;B2;C3)." },
  { topic: "excel-grundlagen", front: "Doppelpunkt in einer Formel", back: "Markiert einen zusammenhängenden Zellbereich, z. B. A1:A8 = alle Zellen von A1 bis A8." },
  { topic: "excel-grundlagen", front: "Semikolon in einer Formel", back: "Trennt einzelne, nicht zusammenhängende Zellen oder Argumente voneinander, z. B. =SUMME(A1;B2;C3)." },
  { topic: "excel-grundlagen", front: "SUMME", back: "Addiert alle Werte in einem Zellbereich, z. B. =SUMME(A1:A8)." },
  { topic: "excel-grundlagen", front: "MIN", back: "Gibt den kleinsten Wert in einem Zellbereich zurück, z. B. =MIN(A1:A8)." },
  { topic: "excel-grundlagen", front: "MAX", back: "Gibt den größten Wert in einem Zellbereich zurück, z. B. =MAX(A1:A8)." },
  { topic: "excel-grundlagen", front: "MITTELWERT", back: "Berechnet den Durchschnitt aller Werte in einem Zellbereich, z. B. =MITTELWERT(A1:A8)." },
  { topic: "excel-grundlagen", front: "ANZAHL", back: "Zählt, wie viele Zellen in einem Bereich eine Zahl enthalten, z. B. =ANZAHL(A1:A8)." },
  { topic: "excel-grundlagen", front: "ANZAHL2", back: "Zählt alle nicht leeren Zellen in einem Bereich – egal ob Zahl oder Text, z. B. =ANZAHL2(A1:A8)." },
  { topic: "excel-grundlagen", front: "Merksatz zur Syntax", back: "\"Syntax ist am wichtigsten. Die Logik kommt von mir, das Rechnen übernimmt Excel.\"" },
  { topic: "excel-bezuege", front: "Relativer Bezug", back: "Z. B. A2 – passt sich beim Kopieren/Ziehen der Formel automatisch an die neue Zeile/Spalte an." },
  { topic: "excel-bezuege", front: "Absoluter Bezug", back: "Z. B. $A$2 – Spalte UND Zeile sind mit $ fest verankert, ändert sich beim Kopieren nicht." },
  { topic: "excel-bezuege", front: "Gemischter Bezug", back: "Z. B. $A2 oder A$2 – nur Spalte ODER nur Zeile ist mit $ fest verankert, der andere Teil bleibt relativ." },
  { topic: "excel-bezuege", front: "$-Zeichen vor dem Spaltenbuchstaben (z. B. $A2)", back: "Hält die Spalte A fest, die Zeile bleibt beim Kopieren variabel." },
  { topic: "excel-bezuege", front: "$-Zeichen vor der Zeilennummer (z. B. A$2)", back: "Hält die Zeile 2 fest, die Spalte bleibt beim Kopieren variabel." },
  { topic: "excel-bezuege", front: "Wann braucht man einen absoluten Bezug?", back: "Wenn eine Formel beim Kopieren/Ziehen immer auf dieselbe feste Zelle zeigen soll, z. B. auf einen festen Bezugswert wie den Zielumsatz in $B$51." },
  { topic: "excel-bezuege", front: "F4-Taste", back: "Schaltet in Excel eine markierte Zellreferenz schnell zwischen relativ, absolut und gemischt um." },
  { topic: "excel-und-oder", front: "UND-Funktion", back: "Prüft mehrere Bedingungen gleichzeitig – das Ergebnis ist nur WAHR, wenn ALLE Bedingungen erfüllt sind." },
  { topic: "excel-und-oder", front: "ODER-Funktion", back: "Prüft mehrere Bedingungen – das Ergebnis ist WAHR, wenn MINDESTENS EINE Bedingung erfüllt ist." },
  { topic: "excel-und-oder", front: "Syntax von UND/ODER", back: "=UND(Bedingung1;Bedingung2;...) bzw. =ODER(Bedingung1;Bedingung2;...) – Bedingungen werden durch Semikolon getrennt." },
  { topic: "excel-und-oder", front: "Ergebnis von UND/ODER", back: "Immer ein Wahrheitswert: WAHR oder FALSCH." },
  { topic: "excel-und-oder", front: "Signalwort für UND", back: "\"und\", \"gleichzeitig\", \"sowohl als auch\" im Aufgabentext deuten auf die UND-Funktion hin." },
  { topic: "excel-und-oder", front: "Signalwort für ODER", back: "\"oder\", \"mindestens eines von beiden\" im Aufgabentext deuten auf die ODER-Funktion hin." },
  { topic: "excel-und-oder", front: "Reihenfolge der Bedingungen bei UND/ODER", back: "Die Reihenfolge der Bedingungen innerhalb der Klammer spielt für das Ergebnis keine Rolle – nur ob sie erfüllt sind, zählt." },
];

